SELECT count(*) FROM keyword, movie_keyword, title, cast_info, movie_info, name, kind_type, role_type, movie_companies WHERE movie_keyword.keyword_id = keyword.id AND movie_keyword.movie_id = title.id AND cast_info.movie_id = title.id AND movie_info.movie_id = title.id AND cast_info.person_id = name.id AND title.kind_id = kind_type.id AND cast_info.role_id = role_type.id AND movie_companies.movie_id = title.id;